'use strict';

/**
* Compute the Cartesian square for a double-precision floating-point strided array.
*
* @module @stdlib/blas-ext-base-dcartesian-square
*
* @example
* import Float64Array from '@stdlib/array-float64';
* import dcartesianSquare from '@stdlib/blas-ext-base-dcartesian-square';
*
* var x = new Float64Array( [ 1.0, 2.0 ] );
* var out = new Float64Array( 8 );
*
* dcartesianSquare( 'row-major', x.length, x, 1, out, 2 );
* // out => <Float64Array>[ 1.0, 1.0, 1.0, 2.0, 2.0, 1.0, 2.0, 2.0 ]
*
* @example
* import Float64Array from '@stdlib/array-float64';
* import dcartesianSquare from '@stdlib/blas-ext-base-dcartesian-square';
*
* var x = new Float64Array( [ 1.0, 2.0 ] );
* var out = new Float64Array( 8 );
*
* dcartesianSquare.ndarray( x.length, x, 1, 0, out, 2, 1, 0 );
* // out => <Float64Array>[ 1.0, 1.0, 1.0, 2.0, 2.0, 1.0, 2.0, 2.0 ]
*/

// MODULES //

var join = require( 'path' ).join;
import tryRequire from '@stdlib/utils-try-require';
import isError from '@stdlib/assert-is-error';
import main from './main.js';


// MAIN //

var dcartesianSquare;
var tmp = tryRequire( join( __dirname, './native.js' ) );
if ( isError( tmp ) ) {
	dcartesianSquare = main;
} else {
	dcartesianSquare = tmp;
}


// EXPORTS //

export default dcartesianSquare;

