'use strict';

// MODULES //

import stride2offset from '@stdlib/strided-base-stride2offset';
import ndarray from './ndarray.js';


// MAIN //

/**
* Returns the index of the first falsy element in a strided array.
*
* ## Notes
*
* -   If unable to find a falsy element, the function returns `-1`.
*
* @param {PositiveInteger} N - number of indexed elements
* @param {Collection} x - input array
* @param {integer} strideX - stride length
* @returns {integer} index
*
* @example
* var x = [ 1.0, 3.0, 0.0, 2.0, 4.0, 1.0, -1.0, 3.0 ];
*
* var idx = gindexOfFalsy( x.length, x, 1 );
* // returns 2
*/
function gindexOfFalsy( N, x, strideX ) {
	return ndarray( N, x, strideX, stride2offset( N, strideX ) );
}


// EXPORTS //

export default gindexOfFalsy;
