'use strict';

/**
* Fill a single-precision floating-point strided array with linearly spaced numeric elements which increment by `1` starting from a specified value.
*
* @module @stdlib/blas-ext-base-sunitspace
*
* @example
* import Float32Array from '@stdlib/array-float32';
* import sunitspace from '@stdlib/blas-ext-base-sunitspace';
*
* var x = new Float32Array( [ 0.0, 0.0, 0.0, 0.0 ] );
*
* sunitspace( x.length, 3.0, x, 1 );
* // x => <Float32Array>[ 3.0, 4.0, 5.0, 6.0 ]
*
* @example
* import Float32Array from '@stdlib/array-float32';
* import sunitspace from '@stdlib/blas-ext-base-sunitspace';
*
* var x = new Float32Array( [ 0.0, 0.0, 0.0, 0.0 ] );
*
* sunitspace.ndarray( x.length, 3.0, x, 1, 0 );
* // x => <Float32Array>[ 3.0, 4.0, 5.0, 6.0 ]
*/

// MODULES //

var join = require( 'path' ).join;
import tryRequire from '@stdlib/utils-try-require';
import isError from '@stdlib/assert-is-error';
import main from './main.js';


// MAIN //

var sunitspace;
var tmp = tryRequire( join( __dirname, './native.js' ) );
if ( isError( tmp ) ) {
	sunitspace = main;
} else {
	sunitspace = tmp;
}


// EXPORTS //

export default sunitspace;

// exports: { "ndarray": "sunitspace.ndarray" }
