'use strict';

/**
* Fill a single-precision floating-point strided array with linearly spaced numeric elements which increment by `1` starting from zero.
*
* @module @stdlib/blas-ext-base-szero-to
*
* @example
* import Float32Array from '@stdlib/array-float32';
* import szeroTo from '@stdlib/blas-ext-base-szero-to';
*
* var x = new Float32Array( [ 0.0, 0.0, 0.0, 0.0 ] );
*
* szeroTo( x.length, x, 1 );
* // x => <Float32Array>[ 0.0, 1.0, 2.0, 3.0 ]
*
* @example
* import Float32Array from '@stdlib/array-float32';
* import szeroTo from '@stdlib/blas-ext-base-szero-to';
*
* var x = new Float32Array( [ 0.0, 0.0, 0.0, 0.0 ] );
*
* szeroTo.ndarray( x.length, x, 1, 0 );
* // x => <Float32Array>[ 0.0, 1.0, 2.0, 3.0 ]
*/

// MODULES //

var join = require( 'path' ).join;
import tryRequire from '@stdlib/utils-try-require';
import isError from '@stdlib/assert-is-error';
import main from './main.js';


// MAIN //

var szeroTo;
var tmp = tryRequire( join( __dirname, './native.js' ) );
if ( isError( tmp ) ) {
	szeroTo = main;
} else {
	szeroTo = tmp;
}


// EXPORTS //

export default szeroTo;

// exports: { "ndarray": "szeroTo.ndarray" }
