'use strict';

/**
* Test whether every element in a strided array is falsy.
*
* @module @stdlib/blas-ext-base-gnone
*
* @example
* import gnone from '@stdlib/blas-ext-base-gnone';
*
* var x = [ 0, 0, 1, 1 ];
*
* var o = gnone( x.length, x, 1 );
* // returns false
*
* @example
* import gnone from '@stdlib/blas-ext-base-gnone';
*
* var x = [ 0, 0, 1, 1 ];
*
* var o = gnone.ndarray( x.length, x, 1, 0 );
* // returns false
*/

// MODULES //

import setReadOnly from '@stdlib/utils-define-nonenumerable-read-only-property';
import main from './main.js';
import ndarray from './ndarray.js';


// MAIN //

setReadOnly( main, 'ndarray', ndarray );


// EXPORTS //

export default main;
