'use strict';

/**
* Cumulatively test whether at least `k` elements in a double-precision floating-point strided array are truthy.
*
* @module @stdlib/blas-ext-base-dcusome
*
* @example
* import Float64Array from '@stdlib/array-float64';
* import BooleanArray from '@stdlib/array-bool';
* import dcusome from '@stdlib/blas-ext-base-dcusome';
*
* var x = new Float64Array( [ 0.0, 0.0, 1.0, 1.0, 1.0 ] );
* var out = new BooleanArray( 5 );
*
* dcusome( x.length, 2, x, 1, out, 1 );
* // out => <BooleanArray>[ false, false, false, true, true ]
*
* @example
* import Float64Array from '@stdlib/array-float64';
* import BooleanArray from '@stdlib/array-bool';
* import dcusome from '@stdlib/blas-ext-base-dcusome';
*
* var x = new Float64Array( [ 0.0, 0.0, 1.0, 1.0, 1.0 ] );
* var out = new BooleanArray( 5 );
*
* dcusome.ndarray( x.length, 2, x, 1, 0, out, 1, 0 );
* // out => <BooleanArray>[ false, false, false, true, true ]
*/

// MODULES //

var join = require( 'path' ).join;
import tryRequire from '@stdlib/utils-try-require';
import isError from '@stdlib/assert-is-error';
import main from './main.js';


// MAIN //

var dcusome;
var tmp = tryRequire( join( __dirname, './native.js' ) );
if ( isError( tmp ) ) {
	dcusome = main;
} else {
	dcusome = tmp;
}


// EXPORTS //

export default dcusome;

// exports: { "ndarray": "dcusome.ndarray" }
