'use strict';

/**
* Return the index of the first truthy element in a double-precision floating-point strided array.
*
* @module @stdlib/blas-ext-base-dindex-of-truthy
*
* @example
* import Float64Array from '@stdlib/array-float64';
* import dindexOfTruthy from '@stdlib/blas-ext-base-dindex-of-truthy';
*
* var x = new Float64Array( [ 0.0, 0.0, 3.0, 0.0, 4.0, 0.0, -1.0, 3.0 ] );
*
* var idx = dindexOfTruthy( x.length, x, 1 );
* // returns 2
*
* @example
* import Float64Array from '@stdlib/array-float64';
* import dindexOfTruthy from '@stdlib/blas-ext-base-dindex-of-truthy';
*
* var x = new Float64Array( [ 0.0, 0.0, 3.0, 0.0, 4.0, 0.0, -1.0, 3.0 ] );
*
* var idx = dindexOfTruthy.ndarray( x.length, x, 1, 0 );
* // returns 2
*/

// MODULES //

var join = require( 'path' ).join;
import tryRequire from '@stdlib/utils-try-require';
import isError from '@stdlib/assert-is-error';
import main from './main.js';


// MAIN //

var dindexOfTruthy;
var tmp = tryRequire( join( __dirname, './native.js' ) );
if ( isError( tmp ) ) {
	dindexOfTruthy = main;
} else {
	dindexOfTruthy = tmp;
}


// EXPORTS //

export default dindexOfTruthy;

// exports: { "ndarray": "dindexOfTruthy.ndarray" }
